+fn ns_sprintrrf_rejects_tracked_unterminated_name() {
+    use frankenlibc_abi::resolv_abi::ns_sprintrrf;
+    let cname = malloc_unterminated(b"foo.com");
+    let mut buf = [0u8; 64];
+    let n = unsafe {
+        ns_sprintrrf(
+            std::ptr::null(),
+            0,
+            cname.as_ptr(),
+            1,
+            1,
+            3600,
+            [127u8, 0, 0, 1].as_ptr(),
+            4,
+            std::ptr::null(),
+            std::ptr::null(),
+            buf.as_mut_ptr() as *mut c_char,
+            buf.len(),
+        )
+    };
+    assert_eq!(n, -1);
